def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        base_score = 0.0
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        penalty_factor = 1.0
        bonus_factor = 1.0
        complexity = 0.0
        exponential_decay = 1.0
        subtle_adjustment = 1.0
        for outer in range(1, 15):
            if outer % 2 == 0:
                penalty_factor *= (1.03 + 0.005 * outer)
            elif outer % 3 == 0:
                penalty_factor *= (0.97 - 0.007 * outer)
            else:
                penalty_factor *= (1.0 + 0.002 * outer)
            for inner in range(1, outer + 2):
                mod_val = (cap * inner + outer) % 13
                if mod_val == 0:
                    complexity += np.sin(outer * ratio + inner) * 0.4
                elif mod_val % 2 == 0:
                    complexity -= np.log1p(abs(ratio - 0.5)) / (inner + outer)
                else:
                    complexity += np.sqrt(abs(ratio - 0.3)) / (inner + 1)
                if (cap + inner * outer) % 11 == 0:
                    bonus_factor *= 1.06
                elif (cap - inner * outer) % 9 == 0:
                    bonus_factor *= 0.94
                if inner == 3 and outer > 5:
                    for deep in range(1, 4):
                        diff = cap - item * (deep**3 + outer)
                        if diff > 0:
                            if (diff + deep) % (outer + 3) == 0:
                                penalty_factor -= np.exp(-diff / (deep + 2)) / (outer + 1)
                            else:
                                penalty_factor += np.log1p(diff) / (deep + outer)
                        else:
                            penalty_factor += abs(diff) ** 1.5 / (deep + outer + 1)
                if ratio > 0.8 and outer % 4 == 0:
                    subtle_adjustment *= 1.08 + 0.015 * inner - 0.005 * outer
                elif ratio < 0.25 and outer % 5 == 0:
                    subtle_adjustment *= 0.88 - 0.012 * inner + 0.007 * outer
            exp_component = np.exp(-((ratio - 0.5) ** 2) * outer / 10)
            base_score += (outer ** 1.5) * exp_component * penalty_factor * bonus_factor
            if outer % 6 == 0:
                exponential_decay *= 0.93 + 0.004 * outer
            else:
                exponential_decay *= 1.01 - 0.003 * outer
        base_score = base_score * exponential_decay + complexity * 0.7
        base_score *= subtle_adjustment
        if base_score <= 0:
            priorities[i] = -base_score * (np.log1p(cap + item) + np.sqrt(cap/2 + 1)) * 1.1
        else:
            if cap > item * 5:
                priorities[i] = -base_score / (np.sqrt(cap) + 2) * (1 + ratio) * 1.2
            else:
                priorities[i] = -base_score / (cap + 4) * np.exp(-ratio**2) * 0.95
        if ratio > 0.9:
            priorities[i] *= 1.18 + 0.02 * (i % 3)
        elif ratio < 0.1:
            priorities[i] *= 0.7 - 0.01 * (i % 4)
        if cap % 3 == 0:
            priorities[i] *= 0.97
        elif cap % 5 == 0:
            priorities[i] *= 1.04
        else:
            priorities[i] *= 1.01
    return priorities
